#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int **a = (int**)malloc(N*sizeof(int*));
        for(int i=0;i<N;i++){
            a[i]=(int*)malloc(N*sizeof(int));
            for(int j=0;j<N;j++) scanf("%d",&a[i][j]);
        }
        for(int i=N-1;i>=0;i--){
            for(int j=N-1;j>=0;j--){
                printf("%d",a[i][j]);
                if(j) printf(" ");
            }
            printf("\n");
        }
        for(int i=0;i<N;i++) free(a[i]);
        free(a);
    }
    return 0;
}

