const fs = require('fs');
const input = fs.readFileSync(0,'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let output = [];
for(let t=0; t<T; t++){
  const N = Number(input[idx++]);
  const mat = Array.from({length:N},()=>Array(N));
  for(let i=0;i<N;i++){
    for(let j=0;j<N;j++) mat[i][j] = Number(input[idx++]);
  }
  for(let i=N-1;i>=0;i--){
    const row = [];
    for(let j=N-1;j>=0;j--) row.push(mat[i][j]);
    output.push(row.join(' '));
  }
}
